{"type":"permission_response","request_id":"perm-1773198588986-1atpwt7","subtype":"success","response":{"updated_input":{"file_path":"/home/ketan/project/flotsam/.claude/worktrees/worktree/client-auth/android/app/src/main/java/com/flotsam/capture/data/SettingsStore.kt","content":"package com.flotsam.capture.data

import android.content.Context
import android.content.SharedPreferences
import androidx.datastore.core.DataStore
import androidx.datastore.preferences.core.Preferences
import androidx.datastore.preferences.core.edit
import androidx.datastore.preferences.core.stringPreferencesKey
import androidx.datastore.preferences.preferencesDataStore
import androidx.security.crypto.EncryptedSharedPreferences
import androidx.security.crypto.MasterKey
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.map

private val Context.dataStore: DataStore<Preferences> by preferencesDataStore(name = "settings")

class SettingsStore(private val context: Context) {

    private companion object {
        val API_URL = stringPreferencesKey("api_url")
        const val ENCRYPTED_PREFS_FILE = "flotsam_secure_prefs"
        const val KEY_JWT_TOKEN = "jwt_token"
    }

    private val encryptedPrefs: SharedPreferences by lazy {
        val masterKey = MasterKey.Builder(context)
            .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
            .build()
        EncryptedSharedPreferences.create(
            context,
            ENCRYPTED_PREFS_FILE,
            masterKey,
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM,
        )
    }

    val apiUrl: Flow<String> = context.dataStore.data.map { prefs ->
        prefs[API_URL] ?: ""
    }

    val jwtToken: Flow<String> = context.dataStore.data.map {
        encryptedPrefs.getString(KEY_JWT_TOKEN, "") ?: ""
    }

    suspend fun setApiUrl(url: String) {
        context.dataStore.edit { prefs -> prefs[API_URL] = url }
    }

    suspend fun setJwtToken(token: String) {
        encryptedPrefs.edit().putString(KEY_JWT_TOKEN, token).apply()
    }
}
"},"permission_updates":[]}}
